import machine
import time
from umqtt.simple import MQTTClient

# Set up WiFi connection
wlan = machine.WLAN(machine.Pin(0))
wlan.active(True)
wlan.connect('your_ssid', 'your_password')

# Wait for WiFi to connect
while not wlan.isconnected():
    pass

# Set up MQTT client
client_id = "ESP32_Sensor"
broker_ip = "192.168.1.100"

client = MQTTClient(client_id, broker_ip)
client.set_last_will(topic="sensors/temp", msg=b"Offline")
client.connect()

while True:
    # Read temperature data from sensor (assuming a DHT11 sensor connected to GPIO 5)
    dht = machine.Pin(5, machine.Pin.IN)
    temp = dht.value()
    
    # Publish temperature reading to MQTT broker
    client.publish("sensors/temp", str(temp).encode())
    
    time.sleep(10)

client.disconnect()